INSERT INTO votes VALUES(2,'Zazen Meditation Timer — Ein einfacher Meditations-Timer mit anpassbaren Abschnitten, Klangschalen und Sitzungsverwaltung.',1779639655049,18,4,2);
INSERT INTO votes VALUES(3,'Ursprünglich entwickelt von Stefan Gaffga. Aktuell gepflegt von Georg Graf.<br><br>Danke an Winfried von <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> für die großartigen Klangschalen-Sounds!',1779639655054,18,4,3);
INSERT INTO votes VALUES(4,'<a href="https://github.com/georgernstgraf/zazentimer/issues">Probleme auf GitHub melden</a>',1779639655059,18,4,4);
INSERT INTO votes VALUES(5,'Diese Anwendung ermöglicht es dem Nutzer, eine Reihe von Meditationssitzungen zu definieren, und bietet einen Timer mit visuellem und akustischem Feedback, wenn ein Teil oder die gesamte Meditation beendet ist.',1779639655063,18,4,5);
INSERT INTO votes VALUES(6,'Entschuldigung, beim Speichern ist ein Fehler aufgetreten.',1779639655069,18,4,6);
