INSERT INTO votes VALUES(61,'Hier kannst du den Namen, die Beschreibung und den Inhalt deiner Sitzung bearbeiten.\n\n NEU ANORDNEN\n Um Elemente neu anzuordnen, halte ein Element gedrückt und\n ziehe es an die neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, wische es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippe ihn einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücke die +-Taste.',1779639655337,18,4,61);
