INSERT INTO votes VALUES(1133,'Тут вы можаце назваць, апісаць і рэдагаваць змест вашай сесіі.\n\n ЗМЯНЕННЕ ПАРАДКУ\n Каб змяніць парадак элементаў, націсніце і ўтрымлівайце элемент і\n перацягніце яго на новае месца.\n\n ВыДАЛЕННЕ\n Каб выдаліць элемент, перасуньце яго направа.\n\n РЭДАГАВАННЕ\n Каб адрэдагаваць секцыю, проста дакраніцеся да яе адзін раз.\n\n ДАДАННЕ\n Каб дадаць новую секцыю, націсніце кнопку +.',1779672200234,6,10,61);
