INSERT INTO votes VALUES(1431,'Тук можете да именувате, опишете и редактирате съдържанието на вашата сесия.\n\n ПРЕНАРЕЖДАНЕ\n За да пренаредите елементите, натиснете дълго върху елемент и\n го плъзнете на новата му позиция.\n\n ИЗТРИВАНЕ\n За да изтриете елемент, плъзнете го надясно.\n\n РЕДАКТИРАНЕ\n За да редактирате секция, просто докоснете я веднъж.\n\n ДОБАВЯНЕ\n За да добавите нова секция, натиснете бутона +.',1779673546824,8,10,61);
