INSERT INTO votes VALUES(2203,'Hier kannst du deine Sitzung benennen, beschreiben und ihren Inhalt bearbeiten.\n\n NEU ANORDNEN\n Um die Reihenfolge zu ändern, drücke lange auf ein Element und\n ziehe es an die neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, wische es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippe ihn einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücke die +-Taste.',1779676097520,18,10,61);
