INSERT INTO votes VALUES(3394,'Δημιουργήθηκε αρχικά από τον Stefan Gaffga. Συντηρείται επί του παρόντος από τον Georg Graf.<br><br>Ευχαριστούμε τον Winfried από το <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> για την παροχή τόσο εξαιρετικών Ήχων Καμπάνας!',1779681642881,21,10,3);
