INSERT INTO votes VALUES(3452,'Εδώ μπορείτε να ονομάσετε, να περιγράψετε και να επεξεργαστείτε τα περιεχόμενα της Συνεδρίας σας.\n\n ΑΝΑΔΙΑΤΑΞΗ\n Για να αναδιατάξετε τα στοιχεία, πιέστε παρατεταμένα σε ένα στοιχείο και\n σύρετέ το στη νέα του θέση.\n\n ΔΙΑΓΡΑΦΗ\n Για να διαγράψετε ένα στοιχείο, μετακινήστε το δεξιά.\n\n ΕΠΕΞΕΡΓΑΣΙΑ\n Για να επεξεργαστείτε μια ενότητα, απλά πιέστε την μία φορά.\n\n ΠΡΟΣΘΗΚΗ\n Για να προσθέσετε νέα ενότητα, πιέστε το κουμπί +.',1779681643042,21,10,61);
