INSERT INTO votes VALUES(4222,'اینجا می‌توانید محتوای نشست خود را نام‌گذاری، توصیف و ویرایش کنید.\n\n تغییر ترتیب\n برای تغییر ترتیب موارد، روی یک مورد فشار طولانی دهید و\n آن را به موقعیت جدید بکشید.\n\n حذف\n برای حذف یک مورد، آن را به راست بکشید.\n\n ویرایش\n برای ویرایش یک بخش، فقط یک بار آن را لمس کنید.\n\n افزودن\n برای افزودن بخش جدید، دکمه + را فشار دهید.',1779682766992,26,10,61);
