INSERT INTO votes VALUES(5445,'મૂળ સ્ટેફન ગાફ્ગા દ્વારા બનાવેલું. હાલમાં જ્યોર્જ ગ્રાફ દ્વારા જાળવેલું.<br><br>આટલા ઉત્તમ ઘંટાના અવાજો પ્રદાન કરવા બદલ <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> ના વિનફ્રિડનો આભાર!',1779685116842,34,10,3);
