INSERT INTO votes VALUES(5503,'અહીં તમે તમારા સેશનની સામગ્રીને નામ આપી શકો છો, વર્ણન કરી શકો છો અને સંપાદિત કરી શકો છો.\n\n પુનઃક્રમ\n વસ્તુઓને પુનઃક્રમિત કરવા માટે, વસ્તુ પર લાંબું દબાવો અને\n તેને તેની નવી સ્થિતિમાં ખેંચો.\n\n કાઢી નાખવું\n વસ્તુ કાઢી નાખવા માટે, તેને જમણી તરફ ખસેડો.\n\n સંપાદન\n સેક્શન સંપાદિત કરવા માટે, ફક્ત એકવાર તેને સ્પર્શ કરો.\n\n ઉમેરો\n નવું સેક્શન ઉમેરવા માટે, + બટન દબાવો.',1779685116982,34,10,61);
