INSERT INTO votes VALUES(7197,'Hér getur þú nefnt, lýst og breytt innihaldi setunnar þinnar.\n\n ENDURRÖÐUN\n Til að endurraða atriðum, ýttu lengi á atriði og\n dragaðu það á nýjan stað.\n\n EYÐING\n Til að eyða atriði, færðu það til hægri.\n\n BREYTING\n Til að breyta hluta, ýttu á hann einu sinni.\n\n BÆTA VIÐ\n Til að bæta við nýjum hluta, ýttu á + hnappinn.',1779687554750,45,10,61);
