INSERT INTO votes VALUES(8737,'Бул жерде сессияңыздын мазмунун атай аласыз, сүрөттөй аласыз жана түзөтө аласыз.\n\n ИРЭЭТТӨӨ\n Элементтерди кайра ирээттөө үчүн, элементти узак басып,\n жаңы ордуна сүйрөңүз.\n\n ӨЧҮРҮҮ\n Элементти өчүрүү үчүн, аны оңго жылдырыңыз.\n\n ТҮЗӨТҮҮ\n Бөлүктү түзөтүү үчүн, бир жолу басыңыз.\n\n КОШУУ\n Жаңы бөлүк кошуу үчүн, + баскычын басыңыз.',1779690706244,56,10,61);
