INSERT INTO votes VALUES(10807,'ഇവിടെ നിങ്ങൾക്ക് നിങ്ങളുടെ സെഷന്റെ ഉള്ളടക്കം നാമകരണം ചെയ്യാനും വിവരിക്കാനും എഡിറ്റ് ചെയ്യാനും കഴിയും.\n\n വീണ്ടും ക്രമീകരിക്കൽ\n ഇനങ്ങൾ വീണ്ടും ക്രമീകരിക്കാൻ, ഒരു ഇനത്തിൽ ദീർഘനേരം അമർത്തി അതിനെ\n പുതിയ സ്ഥാനത്തേക്ക് വലിച്ചിടുക.\n\n ഇല്ലാതാക്കൽ\n ഒരു ഇനം ഇല്ലാതാക്കാൻ, അതിനെ വലത്തേക്ക് നീക്കുക.\n\n എഡിറ്റ് ചെയ്യൽ\n ഒരു വിഭാഗം എഡിറ്റ് ചെയ്യാൻ, അതിൽ ഒരിക്കൽ സ്പർശിക്കുക.\n\n ചേർക്കൽ\n പുതിയ വിഭാഗം ചേർക്കാൻ, + ബട്ടൺ അമർത്തുക.',1779703180610,68,10,61);
