INSERT INTO votes VALUES(12599,'ਇਹ ਐਪਲੀਕੇਸ਼ਨ ਉਪਭੋਗਤਾ ਨੂੰ ਧਿਆਨ ਸੈਸ਼ਨਾਂ ਦਾ ਸੈੱਟ ਪਰਿਭਾਸ਼ਿਤ ਕਰਨ ਦਿੰਦੀ ਹੈ ਅਤੇ ਇੱਕ ਟਾਈਮਰ ਪ੍ਰਦਾਨ ਕਰਦੀ ਹੈ ਜੋ ਧਿਆਨ ਦਾ ਕੋਈ ਹਿੱਸਾ ਜਾਂ ਪੂਰਾ ਧਿਆਨ ਖਤਮ ਹੋਣ ''ਤੇ ਦ੍ਰਿਸ਼ਟੀ ਅਤੇ ਸੁਣਨਯੋਗ ਸੰਕੇਤ ਦਿੰਦਾ ਹੈ।',1779706735967,81,10,5);
