INSERT INTO votes VALUES(13733,'अत्र भवान् स्वस्य सत्रस्य विषयाणां नामकरणं, वर्णनं, सम्पादनं च कर्तुं शक्नोति।\n\n पुनर्व्यवस्थापनम्\n वस्तूनि पुनर्व्यवस्थापयितुं, कस्यचित् वस्तुनः दीर्घतया स्पृशतु तथा च\n तत् स्वस्य नवीनस्थानं प्रति कर्षतु।\n\n विलोपनम्\n कस्यचित् वस्तुः विलोपयितुं, तत् दक्षिणतः गमयतु।\n\n सम्पादनम्\n खण्डं सम्पादयितुम्, केवलम् एकवारं स्पृशतु।\n\n योजनम्\n नूतनखण्डं योजयितुं, + बटन् दाबयतु।',1779708206603,91,10,61);
