INSERT INTO votes VALUES(14349,'Овде можете именовати, описати и уредити садржај ваше сесије.\n\n ПРЕРЕЂИВАЊЕ\n Да бисте променили редослед, дуго притисните ставку и\n превуците је на нову позицију.\n\n БРИСАЊЕ\n Да бисте обрисали ставку, превуците је удесно.\n\n УРЕЂИВАЊЕ\n Да бисте уредили секцију, само је једном додирните.\n\n ДОДАВАЊЕ\n Да бисте додали нову секцију, притисните дугме +.',1779709030684,101,10,61);
