INSERT INTO votes VALUES(14906,'Zazen தியான நேரங்காட்டி — தனிப்பயனாக்கக்கூடிய பிரிவுகள், மணி ஒலிகள் மற்றும் அமர்வு மேலாண்மை கொண்ட எளிய தியான நேரங்காட்டி.',1779710150054,105,10,2);
INSERT INTO votes VALUES(14907,'முதலில் Stefan Gaffga ஆல் உருவாக்கப்பட்டது. தற்போது Georg Graf ஆல் பராமரிக்கப்படுகிறது.<br><br>இவ்வளவு அருமையான மணி ஒலிகளை வழங்கிய <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> இன் Winfried க்கு நன்றி!',1779710150058,105,10,3);
INSERT INTO votes VALUES(14908,'<a href="https://github.com/georgernstgraf/zazentimer/issues">GitHub-ல் சிக்கல்களைப் புகாரளிக்கவும்</a>',1779710150060,105,10,4);
INSERT INTO votes VALUES(14909,'இந்த பயன்பாடு பயனர் தியான அமர்வுகளின் தொகுப்பை வரையறுக்க அனுமதிக்கிறது, மேலும் தியானத்தின் ஒரு பகுதி அல்லது முழுமையாக முடிந்ததும் காட்சி மற்றும் கேட்கக்கூடிய கருத்துடன் ஒரு நேரங்காட்டியை வழங்குகிறது.',1779710150063,105,10,5);
