INSERT INTO votes VALUES(17810,'Εδώ μπορείτε να ονομάσετε, να περιγράψετε και να επεξεργαστείτε τα περιεχόμενα της Συνεδρίας σας.\n\n ΑΝΑΔΙΑΤΑΞΗ\n Για αναδιάταξη των στοιχείων, πατήστε παρατεταμένα ένα στοιχείο και\n σύρετέ το στη νέα του θέση.\n\n ΔΙΑΓΡΑΦΗ\n Για διαγραφή ενός στοιχείου, μετακινήστε το προς τα δεξιά.\n\n ΕΠΕΞΕΡΓΑΣΙΑ\n Για επεξεργασία μιας ενότητας, απλώς αγγίξτε την μία φορά.\n\n ΠΡΟΣΘΗΚΗ\n Για προσθήκη νέας ενότητας, πατήστε το κουμπί +.',1779729891534,21,6,61);
