INSERT INTO votes VALUES(18892,'यहाँ आप अपने सत्र की सामग्री को नाम दे सकते हैं, वर्णन कर सकते हैं और संपादित कर सकते हैं।\n\n पुनर्क्रम\n आइटम को पुनर्व्यवस्थित करने के लिए, किसी आइटम पर देर तक दबाएँ और\n उसे उसकी नई स्थिति पर खींचें।\n\n हटाना\n किसी आइटम को हटाने के लिए, उसे दाईं ओर ले जाएँ।\n\n संपादन\n किसी अनुभाग को संपादित करने के लिए, बस उसे एक बार स्पर्श करें।\n\n जोड़ें\n नया अनुभाग जोड़ने के लिए, + बटन दबाएँ।',1779731537511,37,6,61);
