INSERT INTO votes VALUES(20432,'ਇੱਥੇ ਤੁਸੀਂ ਆਪਣੇ ਸੈਸ਼ਨ ਦੀ ਸਮੱਗਰੀ ਨੂੰ ਨਾਮ ਦੇ ਸਕਦੇ, ਵਰਣਨ ਕਰ ਸਕਦੇ ਅਤੇ ਸੋਧ ਸਕਦੇ ਹੋ।\n\n ਮੁੜ-ਕ੍ਰਮਬੱਧ\n ਆਈਟਮਾਂ ਨੂੰ ਮੁੜ-ਕ੍ਰਮਬੱਧ ਕਰਨ ਲਈ, ਕਿਸੇ ਆਈਟਮ ਨੂੰ ਲੰਬਾ ਦਬਾਓ ਅਤੇ\n ਇਸਨੂੰ ਇਸਦੀ ਨਵੀਂ ਸਥਿਤੀ ’ਤੇ ਖਿੱਚੋ।\n\n ਮਿਟਾਉਣਾ\n ਕਿਸੇ ਆਈਟਮ ਨੂੰ ਮਿਟਾਉਣ ਲਈ, ਇਸਨੂੰ ਸੱਜੇ ਪਾਸੇ ਲੈ ਜਾਓ।\n\n ਸੋਧ\n ਕਿਸੇ ਭਾਗ ਨੂੰ ਸੋਧਣ ਲਈ, ਇਸਨੂੰ ਸਿਰਫ਼ ਇੱਕ ਵਾਰ ਛੋਹੋ।\n\n ਸ਼ਾਮਲ\n ਨਵਾਂ ਭਾਗ ਜੋੜਨ ਲਈ, + ਬਟਨ ਦਬਾਓ।',1779733847413,81,6,61);
