INSERT INTO votes VALUES(21356,'Здесь вы можете назвать, описать и изменить содержимое вашей сессии.\n\n ПЕРЕСТАНОВКА\n Чтобы изменить порядок элементов, нажмите и удерживайте элемент,\n затем перетащите его на новое место.\n\n УДАЛЕНИЕ\n Чтобы удалить элемент, смахните его вправо.\n\n РЕДАКТИРОВАНИЕ\n Чтобы изменить секцию, просто коснитесь её один раз.\n\n ДОБАВЛЕНИЕ\n Чтобы добавить новую секцию, нажмите кнопку +.',1779734681844,89,6,61);
