INSERT INTO votes VALUES(23565,'Тут вы можаце назваць, апісаць і рэдагаваць змест вашай сесіі.\n\n ЗМЕНА ПАРАДКУ\n Каб змяніць парадак элементаў, націсніце на элемент і ўтрымлівайце,\n а затым перацягніце яго на новае месца.\n\n ВЫДАЛЕННЕ\n Каб выдаліць элемент, перасуньце яго направа.\n\n РЭДАГАВАННЕ\n Каб рэдагаваць раздзел, проста націсніце на яго адзін раз.\n\n ДАДАВАННЕ\n Каб дадаць новы раздзел, націсніце кнопку +.',1779746770595,6,9,61);
