INSERT INTO votes VALUES(24518,'Diese App erhebt keine personenbezogenen Daten – sie verwendet auch keine IP-Adressen oder andere technologiebezogene Daten, noch erhebt, verarbeitet oder nutzt sie solche in irgendeiner Weise.',1779754174569,18,9,100);
