INSERT INTO votes VALUES(25801,'Hier können Sie Ihre Sitzung benennen, beschreiben und den Inhalt bearbeiten.\n\n NEUORDNEN\n Um die Elemente neu anzuordnen, halten Sie ein Element lange gedrückt und\n ziehen Sie es an die neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, schieben Sie es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippen Sie ihn einfach einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücken Sie die + Taste.',1779790674662,39,9,61);
