INSERT INTO votes VALUES(30196,'Монда сез Сезнең Сессиягезнең эчтәлеген исемләп, тасвирлый һәм редакцияли аласыз.\n\n ЯҢАДАН ТӘРТИПЛӘҮ\n Элементларны яңадан тәртипләү өчен, берәр элементны озак басыгыз һәм\n аны яңа урынга күчерегез.\n\n БЕТЕРҮ\n Элементны бетерү өчен, аны уңга күчерегез.\n\n РЕДАКЦИЯ\n Бүлекне редакцияләү өчен, аңа бер тапкыр тегегез.\n\n ӨСТӘҮ\n Яңа бүлек өстәү өчен, + төймәсенә басыгыз.',1779814255439,112,9,61);
