INSERT INTO votes VALUES(30440,'Ở đây bạn có thể đặt tên, mô tả và chỉnh sửa nội dung buổi thiền của mình.\n\n SẮP XẾP LẠI\n Để sắp xếp lại các mục, nhấn giữ vào một mục và\n kéo nó đến vị trí mới.\n\n XÓA\n Để xóa một mục, vuốt sang phải.\n\n CHỈNH SỬA\n Để chỉnh sửa một phần, chỉ cần chạm vào nó một lần.\n\n THÊM\n Để thêm một phần mới, nhấn nút +.',1779815951789,117,9,61);
