INSERT INTO votes VALUES(30870,'هنا يمكنك تسمية ووصف وتحرير محتوى جلستك.\n\n إعادة الترتيب\n لإعادة ترتيب العناصر، اضغط ضغطة طويلة على عنصر\n واسحبه إلى موضعه الجديد.\n\n الحذف\n لحذف عنصر، حركه إلى اليمين.\n\n تحرير\n لتحرير قسم، فقط المسه مرة واحدة.\n\n إضافة\n لإضافة قسم جديد، اضغط على زر +.',1779818726886,3,7,61);
