INSERT INTO votes VALUES(31171,'Тук можете да наименувате, опишете и редактирате съдържанието на вашата сесия.\n\n ПРЕПОРЕЖДАНЕ\n За да пренаредите елементите, натиснете продължително върху елемент и\n го плъзнете до новата му позиция.\n\n ИЗТРИВАНЕ\n За да изтриете елемент, плъзнете го надясно.\n\n РЕДАКТИРАНЕ\n За да редактирате секция, просто я докоснете веднъж.\n\n ДОБАВЯНЕ\n За да добавите нова секция, натиснете бутона +.',1779819133058,7,7,61);
