INSERT INTO votes VALUES(31394,'এখানে আপনি আপনার সেশনের বিষয়বস্তু নাম দিতে, বর্ণনা করতে এবং সম্পাদনা করতে পারেন।\n\n পুনরায় সাজানো\n আইটেমগুলি পুনরায় সাজাতে, একটি আইটেম দীর্ঘক্ষণ চাপ দিন এবং\n এটিকে তার নতুন অবস্থানে টেনে আনুন।\n\n মুছে ফেলা\n একটি আইটেম মুছে ফেলতে, এটিকে ডানে সরান।\n\n সম্পাদনা\n একটি সেকশন সম্পাদনা করতে, শুধু একবার স্পর্শ করুন।\n\n যোগ করুন\n একটি নতুন সেকশন যোগ করতে, + বোতাম চাপুন।',1779819398031,9,7,61);
