INSERT INTO votes VALUES(32005,'Her kan du navngive, beskrive og redigere indholdet af din session.\n\n OMORDNING\n For at omordne elementerne, tryk længe på et element og\n træk det til sin nye position.\n\n SLETNING\n For at slette et element, flyt det til højre.\n\n REDIGER\n For at redigere en sektion, tryk på den én gang.\n\n TILFØJ\n For at tilføje en ny sektion, tryk på + knappen.',1779820171859,17,7,61);
