INSERT INTO votes VALUES(32052,'Ursprünglich erstellt von Stefan Gaffga. Aktuell betreut von Georg Graf.<br><br>Dank an Winfried von <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> für die Bereitstellung dieser tollen Klangschalen-Sounds!',1779820240325,18,7,3);
INSERT INTO votes VALUES(32053,'Diese Anwendung lässt den Benutzer einen Satz von Meditationssitzungen definieren und bietet einen Timer mit visueller und akustischer Rückmeldung, wenn ein Teil oder die gesamte Meditation beendet ist.',1779820240328,18,7,5);
