INSERT INTO votes VALUES(32059,'Reduziert die individuellen Lautstärken der Klangschalen für diese Sitzung.',1779820240342,18,7,28);
INSERT INTO votes VALUES(32060,'Hält den Bildschirm während der Meditation eingeschaltet',1779820240345,18,7,57);
INSERT INTO votes VALUES(32061,'Hier können Sie Ihre Sitzung benennen, beschreiben und den Inhalt bearbeiten.\n\n NEU ANORDNEN\n Um die Elemente neu anzuordnen, drücken Sie lange auf ein Element und\n ziehen Sie es an seine neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, verschieben Sie es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippen Sie einfach einmal darauf.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücken Sie die + Taste.',1779820240348,18,7,61);
INSERT INTO votes VALUES(32062,'Meditation kann nicht gestartet werden: Die ausgewählte Sitzung hat keine Abschnitte.',1779820240351,18,7,79);
INSERT INTO votes VALUES(32063,'Anzahl der Klangschalen',1779820240353,18,7,84);
