INSERT INTO votes VALUES(32113,'Εδώ μπορείτε να ονομάσετε, να περιγράψετε και να επεξεργαστείτε τα περιεχόμενα της Συνεδρίας σας.\n\n ΑΝΑΔΙΑΤΑΞΗ\n Για να αναδιατάξετε τα στοιχεία, πατήστε παρατεταμένα ένα στοιχείο και\n σύρετέ το στη νέα του θέση.\n\n ΔΙΑΓΡΑΦΗ\n Για να διαγράψετε ένα στοιχείο, μετακινήστε το προς τα δεξιά.\n\n ΕΠΕΞΕΡΓΑΣΙΑ\n Για να επεξεργαστείτε μια ενότητα, απλώς αγγίξτε την μία φορά.\n\n ΠΡΟΣΘΗΚΗ\n Για να προσθέσετε μια νέα ενότητα, πατήστε το κουμπί +.',1779820397325,21,7,61);
