INSERT INTO votes VALUES(32587,'در اینجا می‌توانید محتوای جلسه خود را نام‌گذاری، توصیف و ویرایش کنید.\n\n مرتب‌سازی مجدد\n برای مرتب‌سازی مجدد موارد، روی یک مورد فشار طولانی دهید و\n آن را به موقعیت جدید بکشید.\n\n حذف\n برای حذف یک مورد، آن را به راست ببرید.\n\n ویرایش\n برای ویرایش یک بخش، فقط یک بار روی آن ضربه بزنید.\n\n افزودن\n برای افزودن بخش جدید، دکمه + را فشار دهید.',1779821036028,26,7,61);
