INSERT INTO votes VALUES(33084,'Anseo is féidir leat do Sheisiún a ainmniú, a chur síos agus a chuid ábhar a chur in eagar.\n\n ATHORDÚ\n Chun na míreanna a athordú, brúigh go fada ar mhír agus\n tarraing í go dtí a suíomh nua.\n\n SCRISADH\n Chun mír a scriosadh, bog ar dheis í.\n\n CUIR IN EAGAR\n Chun codán a chur in eagar, ná déan ach tadhall uair amháin air.\n\n CUIR LEIS\n Chun codán nua a chur leis, brúigh an cnaipe +.',1779821622051,31,7,61);
