INSERT INTO votes VALUES(33450,'અહીં તમે તમારા સેશનનું નામ આપી શકો છો, વર્ણન કરી શકો છો અને સામગ્રી સંપાદિત કરી શકો છો.\n\n ફરીથી ગોઠવવું\n આઇટમ્સને ફરીથી ગોઠવવા માટે, આઇટમ પર લાંબુ દબાણ કરો અને\n તેને તેની નવી સ્થિતિ પર ખેંચો.\n\n કાઢી નાખવું\n આઇટમ કાઢી નાખવા માટે, તેને જમણી બાજુ ખસેડો.\n\n સંપાદન\n સેક્શન સંપાદિત કરવા માટે, તેને એક વાર સ્પર્શ કરો.\n\n ઉમેરો\n નવું સેક્શન ઉમેરવા માટે, + બટન દબાવો.',1779822088436,34,7,61);
