INSERT INTO votes VALUES(33677,'यहाँ आप अपने सेशन का नाम, विवरण और सामग्री संपादित कर सकते हैं।\n\n पुनः क्रमबद्ध करना\n आइटम को पुनः क्रमबद्ध करने के लिए, किसी आइटम को देर तक दबाएं और\n उसे अपनी नई स्थिति पर खींचें।\n\n हटाना\n किसी आइटम को हटाने के लिए, उसे दाईं ओर ले जाएं।\n\n संपादन\n किसी सेक्शन को संपादित करने के लिए, बस एक बार टच करें।\n\n जोड़ें\n नया सेक्शन जोड़ने के लिए, + बटन दबाएं।',1779822364492,37,7,61);
