INSERT INTO votes VALUES(34262,'Hér geturðu nefnt, lýst og breytt innihaldi setunnar þinnar.\n\n ENDURRÖÐUN\n Til að endurraða atriðum, ýttu lengi á atriði og\n dragðu það á nýja staðsetningu.\n\n EYÐING\n Til að eyða atriði, færðu það til hægri.\n\n BREYTA\n Til að breyta kafla, snertu hann bara einu sinni.\n\n BÆTA VIÐ\n Til að bæta við nýjum kafla, ýttu á + hnappinn.',1779823324185,45,7,61);
