INSERT INTO votes VALUES(35042,'Li vir hûn dikarin navê rûniştina xwe bidin, rave bikin û naveroka wê biguherînin.\n\n JI NÛ VE RÊZKIRIN\n Ji bo ku hûn tiştan ji nû ve rêz bikin, li ser tiştekî dirêj pêbikin û\n bikişînin cihê wê yê nû.\n\n JÊBIRIN\n Ji bo ku hûn tiştekî jê bibin, wê ber bi rastê ve bibin.\n\n GUHÊRTIN\n Ji bo guhertina beşekê, tenê carekê lê bixin.\n\n LÊ ZÊDEKIRIN\n Ji bo lê zêdekirina beşek nû, bişkoka + bikirtînin.',1779824447925,55,7,61);
