INSERT INTO votes VALUES(35652,'Овде можете да го именувате, опишете и уредите содржината на вашата сесија.\n\n РЕОРГАНИЗИРАЊЕ\n За да ги преуредите ставките, притиснете долго на ставка и\n повлечете ја на новата позиција.\n\n БРИШЕЊЕ\n За да избришете ставка, повлечете ја надесно.\n\n УРЕДУВАЊЕ\n За да уредите секција, допрете ја еднаш.\n\n ДОДАВАЊЕ\n За да додадете нова секција, притиснете го копчето +.',1779825372563,67,7,61);
