INSERT INTO votes VALUES(36295,'Hier kunt u de inhoud van uw sessie een naam geven, beschrijven en bewerken.\n\n HERORDEREN\n Om items te herordenen, houd een item lang ingedrukt en\n sleep het naar zijn nieuwe positie.\n\n VERWIJDEREN\n Om een item te verwijderen, verplaats het naar rechts.\n\n BEWERKEN\n Om een sectie te bewerken, tik er gewoon een keer op.\n\n TOEVOEGEN\n Om een nieuwe sectie toe te voegen, druk op de + knop.',1779826374274,76,7,61);
