INSERT INTO votes VALUES(36452,'Oryginalnie stworzony przez Stefana Gaffga. Obecnie utrzymywany przez Georga Grafa.<br><br>Podziękowania dla Winfrieda z <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> za udostępnienie wspaniałych dźwięków dzwonków!',1779826761606,82,7,3);
