INSERT INTO votes VALUES(36478,'Tutaj możesz nazwać, opisać i edytować zawartość swojej sesji.\n\n ZMIANA KOLEJNOŚCI\n Aby zmienić kolejność elementów, naciśnij i przytrzymaj element, a następnie\n przeciągnij go na nowe miejsce.\n\n USUWANIE\n Aby usunąć element, przesuń go w prawo.\n\n EDYCJA\n Aby edytować sekcję, wystarczy dotknąć ją raz.\n\n DODAWANIE\n Aby dodać nową sekcję, naciśnij przycisk +.',1779826761671,82,7,61);
