INSERT INTO votes VALUES(36524,'Aqui você pode nomear, descrever e editar o conteúdo da sua Sessão.\n\n REORDENAR\n Para reordenar os itens, pressione e segure um item e\n arraste-o para a nova posição.\n\n EXCLUIR\n Para excluir um item, mova-o para a direita.\n\n EDITAR\n Para editar uma seção, basta tocá-la uma vez.\n\n ADICIONAR\n Para adicionar uma nova seção, pressione o botão +.',1779826890969,84,7,61);
