INSERT INTO votes VALUES(36804,'Здесь вы можете назвать, описать и отредактировать содержимое вашей сессии.\n\n ИЗМЕНЕНИЕ ПОРЯДКА\n Чтобы изменить порядок элементов, нажмите и удерживайте элемент, затем\n перетащите его на новое место.\n\n УДАЛЕНИЕ\n Чтобы удалить элемент, переместите его вправо.\n\n РЕДАКТИРОВАНИЕ\n Чтобы редактировать секцию, просто коснитесь её один раз.\n\n ДОБАВЛЕНИЕ\n Чтобы добавить новую секцию, нажмите кнопку +.',1779827365525,89,7,61);
