INSERT INTO votes VALUES(36889,'अत्र भवन्तः स्वस्य सत्रस्य विषयान् नाम ददति, वर्णयन्ति, सम्पादयन्ति च।\n\n पुनःक्रमणम्\n वस्तूनि पुनःक्रमयितुं वस्तुनि दीर्घं नोदयतु (long press) च\n तत् नूतनस्थाने कर्षयतु।\n\n विलोपनम्\n वस्तु विलोपयितुं तत् दक्षिणतः नयतु।\n\n सम्पादनम्\n विभागं सम्पादयितुं तत् एकवारं स्पृशन्तु।\n\n योगः\n नूतनं विभागं योजयितुं + बटनं नोदयतु।',1779827534965,91,7,61);
