INSERT INTO votes VALUES(37620,'Ovde možete imenovati, opisati i uređivati sadržaj vaše sesije.\n\n PROMENA REDOSLEDA\n Da promenite redosled, dugo pritisnite stavku i\n prevucite je na novu poziciju.\n\n BRISANJE\n Da obrišete stavku, prevucite je udesno.\n\n UREĐIVANJE\n Da uredite sekciju, samo je dodirnite jednom.\n\n DODAVANJE\n Da dodate novu sekciju, pritisnite + dugme.',1779828649863,5,7,61);
