INSERT INTO votes VALUES(37671,'Här kan du namnge, beskriva och redigera innehållet i din session.\n\n ÄNDRA ORDNING\n För att ändra ordning på objekten, tryck länge på ett objekt och\n dra det till sin nya position.\n\n RADERA\n För att radera ett objekt, flytta det åt höger.\n\n REDIGERA\n För att redigera en sektion, tryck bara på den en gång.\n\n LÄGG TILL\n För att lägga till en ny sektion, tryck på +-knappen.',1779828788726,103,7,61);
