INSERT INTO votes VALUES(37755,'Hapa unaweza kutaja, kuelezea na kuhariri maudhui ya Kipindi chako.\n\n KUPANGA UPYA\n Ili kupanga upya vitu, bonyeza kwa muda kwenye kitu na\n kivute hadi nafasi yake mpya.\n\n KUFUTA\n Ili kufuta kitu, kihame kulia.\n\n KUHARIRI\n Ili kuhariri sehemu, iguse mara moja tu.\n\n KUONGEZA\n Ili kuongeza sehemu mpya, bonyeza kitufe cha +.',1779828934230,104,7,61);
