INSERT INTO votes VALUES(37831,'Zazen தியான டைமர் — தனிப்பயனாக்கக்கூடிய பிரிவுகள், மணி ஒலிகள் மற்றும் அமர்வு மேலாண்மை கொண்ட எளிய தியான டைமர்.',1779829110335,105,7,2);
INSERT INTO votes VALUES(37832,'அசலாக Stefan Gaffga ஆல் உருவாக்கப்பட்டது. தற்போது Georg Graf ஆல் பராமரிக்கப்படுகிறது.<br><br>இத்தகைய சிறந்த மணி ஒலிகளை வழங்கிய <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> இன் Winfried-க்கு நன்றி!',1779829110338,105,7,3);
