INSERT INTO votes VALUES(37877,'இங்கே உங்கள் அமர்வின் உள்ளடக்கத்தை பெயரிட, விவரிக்க மற்றும் திருத்த முடியும்.\n\n வரிசைமாற்றம்\n உருப்படிகளை மீண்டும் வரிசைப்படுத்த, ஒரு உருப்படியை நீண்ட நேரம் அழுத்தி\n அதன் புதிய இடத்திற்கு இழுக்கவும்.\n\n நீக்குதல்\n ஒரு உருப்படியை நீக்க, அதை வலதுபுறம் நகர்த்தவும்.\n\n திருத்து\n ஒரு பிரிவை திருத்த, அதை ஒரு முறை தொடுக்கவும்.\n\n சேர்\n புதிய பிரிவை சேர்க்க, + பொத்தானை அழுத்தவும்.',1779829110453,105,7,61);
