INSERT INTO votes VALUES(37999,'Дар ин ҷо шумо метавонед сессияи худро ном гузоред, тавсиф кунед ва мундариҷаи онро таҳрир кунед.\n\n ТАҒЙИРИ ТАРТИБ\n Барои тағйири тартиби элементҳо, тугмаро дар болои элемент дароз пахш кунед ва\n онро ба мавқеи нав кашед.\n\n НЕСТ КАРДАН\n Барои нест кардани элемент, онро ба тарафи рост ҳаракат диҳед.\n\n ТАҲРИР\n Барои таҳрири бахш, онро як маротиба ламс кунед.\n\n ИЛОВА\n Барои иловаи бахши нав, тугмаи + -ро пахш кунед.',1779829291087,107,7,61);
