INSERT INTO votes VALUES(38566,'Монда сез Сессиягезнең эчтәлеген исемли, тасвирлый һәм төзәтә аласыз.\n\n ТӘРТИБНЕ ҮЗГӘРТҮ\n Элементлар тәртибен үзгәртү өчен, элементка озак басыгыз һәм\n аны яңа урынга күчерегез.\n\n БЕТЕРҮ\n Элементны бетерү өчен, аны уңга күчерегез.\n\n ТӨЗӘТҮ\n Бүлекне төзәтү өчен, аңа бер тапкыр гына тиегез.\n\n ӨСТӘҮ\n Яңа бүлек өстәү өчен, + төймәсенә басыгыз.',1779829965525,112,7,61);
