INSERT INTO votes VALUES(39128,'דאָ קענט איר געבן אַ נאָמען, באַשרײַבן און רעדאַקטירן דעם אינהאַלט פֿון אײַער סעסיע.\n\n אומאָרדענען\n צו אומאָרדענען די עלעמענטן, דריקט לאַנג אויף אַן עלעמענט און\n ציט עס צו זײַן נײַע שטעלע.\n\n מעקן\n צו מעקן אַן עלעמענט, באַוועגט עס צום רעכטן.\n\n רעדאַקטירן\n צו רעדאַקטירן אַ סעקציע, טיפּט נאָר אײן מאָל.\n\n צוגעבן\n צו צוגעבן אַ נײַע סעקציע, דריקט דעם + קנעפּל.',1779830732571,119,7,61);
