INSERT INTO votes VALUES(39250,'Níbí ni o lè fún apá rẹ ní orúkọ, ṣe àpèjúwe, ṣàtúnṣe àwọn ohun tó wà nínú ìrònú rẹ.\n\n ÀTÚNTÒ\n Láti tún àwọn ohun tó, tẹ ohun kan gùn, kí o sì fà á sí ibi tuntun rẹ̀.\n\n PÍPÀ RẸ́\n Láti pa ohun kan rẹ́, mú un lọ sí ọ̀tún.\n\n ṢÀTÚNṢE\n Láti ṣàtúnṣe apá kan, kan an lẹ́ẹ̀kan ṣoṣo.\n\n ṢÀFIKÚN\n Láti ṣàfikún apá tuntun, tẹ bọ́tìnì +.',1779830901096,120,7,61);
