INSERT INTO votes VALUES(39611,'Тук можете да именувате, описвате и редактирате съдържанието на вашата сесия.\n\n ПРЕПОДРЕЖДАНЕ\n За да преподредите елементите, натиснете продължително върху елемент и\n го плъзнете до новата му позиция.\n\n ИЗТРИВАНЕ\n За да изтриете елемент, преместете го надясно.\n\n РЕДАКТИРАНЕ\n За да редактирате секция, просто я докоснете веднъж.\n\n ДОБАВЯНЕ\n За да добавиге нова секция, натиснете бутона +.',1779844679287,7,11,61);
