INSERT INTO votes VALUES(39672,'এখানে আপনি আপনার সেশনের নাম দিতে, বর্ণনা করতে এবং বিষয়বস্তু সম্পাদনা করতে পারেন।\n\n পুনর্ক্রমণ\n আইটমগুলি পুনর্ক্রমণ করতে, একটি আইটমে দীর্ঘক্ষণ টিপুন এবং\n এটিকে নতুন অবস্থানে টেনে আনুন।\n\n মুছুন\n একটি আইটম মুছতে, এটি ডানে সরান।\n\n সম্পাদনা\n একটি বিভাগ সম্পাদনা করতে, এটি একবার স্পর্শ করুন।\n\n যোগ করুন\n একটি নতুন বিভাগ যোগ করতে, + বোতাম টিপুন।',1779844738901,9,11,61);
