INSERT INTO votes VALUES(39931,'Her kan du navngive, beskrive og redigere indholdet af din Session.\n\n OMORGANISERING\n For at omorganisere elementerne, tryk langt på et element og\n træk det til sin nye position.\n\n SLETNING\n For at slette et element, flyt det til højre.\n\n REDIGERING\n For at redigere en sektion, tryk blot på den.\n\n TILFØJ\n For at tilføje en ny sektion, tryk på + knappen.',1779844992985,17,11,61);
