INSERT INTO votes VALUES(39956,'Ursprünglich erstellt von Stefan Gaffga. Wird jetzt von Georg Graf gepflegt.<br><br>Dank an Winfried von <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> für die großartigen Klangschalentöne!',1779845018079,18,11,3);
INSERT INTO votes VALUES(39957,'Diese App ermöglicht es dem Benutzer, eine Reihe von Meditationssitzungen zu definieren, und bietet einen Timer mit visueller und akustischer Rückmeldung, wenn ein Teil oder die gesamte Meditation beendet ist.',1779845018082,18,11,5);
INSERT INTO votes VALUES(39958,'Klangschalenabstand (Sek.)',1779845018084,18,11,18);
