INSERT INTO votes VALUES(39961,'Hält den Bildschirm während der Meditation eingeschaltet',1779845018091,18,11,57);
INSERT INTO votes VALUES(39962,'Hier können Sie Ihre Sitzung benennen, beschreiben und bearbeiten.\n\n NEUANORDNUNG\n Um die Elemente neu anzuordnen, drücken Sie lange auf ein Element und\n ziehen es an die neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, schieben Sie es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippen Sie ihn einfach einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücken Sie die + Schaltfläche.',1779845018094,18,11,61);
INSERT INTO votes VALUES(39963,'Klangschalenanzahl',1779845018095,18,11,84);
