INSERT INTO votes VALUES(39966,'Diese App erfasst keinerlei persönliche Daten - sie verwendet auch keine IP-Adressen oder andere technologiebezogene Daten, noch sammelt, verarbeitet oder nutzt sie diese in irgendeiner Weise.',1779845018103,18,11,100);
