INSERT INTO votes VALUES(40003,'Ĉi tie vi povas nomi, priskribi kaj redakti la enhavon de via Sesio.\n\n REORDIGO\n Por reordigi la erojn, premtenu eron kaj tren ĝin al ĝia nova pozicio.\n\n FORIGADO\n Por forigi eron, movu ĝin dekstren.\n\n REDAKTO\n Por redakti sekcion, tuŝu ĝin unufoje.\n\n ALDONADO\n Por aldoni novan sekcion, premu la + butonon.',1779845103479,22,11,61);
