INSERT INTO votes VALUES(40207,'यहाँ आप अपने सत्र का नाम, विवरण और सामग्री संपादित कर सकते हैं।\n\n पुनर्व्यवस्थित करना\n आइटमों को पुनर्व्यवस्थित करने के लिए, किसी आइटम पर देर तक दबाएँ और\n इसे नए स्थान पर खींचें।\n\n हटाना\n किसी आइटम को हटाने के लिए, इसे दाईं ओर ले जाएँ।\n\n संपादित करना\n किसी अनुभाग को संपादित करने के लिए, बस इसे एक बार छुएँ।\n\n जोड़ना\n एक नया अनुभाग जोड़ने के लिए, + बटन दबाएँ।',1779845474023,37,11,61);
