INSERT INTO votes VALUES(40486,'ここでは、セッションの名前を指定し、説明を得て、内容を編集できます。\n\n 並べ替え\n アイテムを並べ替えるには、アイテムを長押しして\n 新しい位置にドラッグします。\n\n 削除\n アイテムを削除するには、右に移動します。\n\n 編集\n セクションを編集するには、1回タッチします。\n\n 追加\n 新しいセクションを追加するには、+ボタンをタップします。',1779846079171,47,11,61);
