INSERT INTO votes VALUES(41066,'Her kan du gi navn til, beskrive og redigere innholdet i din økt.\n\n OMORDNING\n For å omorganisere elementene, trykk lenge på et element og\n dra det til den nye posisjonen.\n\n SLETTING\n For å slette et element, flytt det til høyre.\n\n REDIGERING\n For å redigere en seksjon, trykk på den én gang.\n\n LEGGE TIL\n For å legge til en ny seksjon, trykk på +-knappen.',1779846664001,74,11,61);
