INSERT INTO votes VALUES(41113,'Hier kunt u de naam, beschrijving en inhoud van uw sessie bewerken.\n\n HERORDEREN\n Om de items te herordenen, houdt u een item lang ingedrukt en\n sleept u het naar de nieuwe positie.\n\n VERWIJDEREN\n Om een item te verwijderen, verplaatst u het naar rechts.\n\n BEWERKEN\n Om een sectie te bewerken, raakt u deze eenmaal aan.\n\n TOEVOEGEN\n Om een nieuwe sectie toe te voegen, drukt u op de + knop.',1779846704481,76,11,61);
