INSERT INTO votes VALUES(41442,'Tu môžete pomenovať, opísať a upraviť obsah vašej relácie.\n\n PRESKUPENIE\n Na preskupenie položiek dlho stlačte položku a\n presuňte ju na novú pozíciu.\n\n MAZANIE\n Na vymazanie položky ju presuňte doprava.\n\n ÚPRAVY\n Na úpravu sekcie ju raz dotknite.\n\n PRIDANIE\n Na pridanie novej sekcie stlačte tlačidlo +.',1779847151293,95,11,61);
