INSERT INTO votes VALUES(41629,'Këtu mund të emëroni, përshkruani dhe modifikoni përmbajtjen e Sesionit tuaj.\n\n RIRENDITJA\n Për të rirenditur elementet, shtypni gjatë mbi një element dhe\n tërhiqeni në pozicionin e ri.\n\n FSHIRJA\n Për të fshirë një element, lëvizeni djathtas.\n\n MODIFIKIMI\n Për të modifikuar një seksion, thjesht prekeni një herë.\n\n SHTIMI\n Për të shtuar një seksion të ri, shtypni butonin +.',1779847406387,100,11,61);
