INSERT INTO votes VALUES(41828,'Ovde možete imenovati, opisati i urediti sadržaj svoje Sesije.\n\n PREUREĐIVANJE\n Da biste preuredili stavke, dugo pritisnite na stavku i\n prevucite je na novu poziciju.\n\n BRISANJE\n Da biste obrisali stavku, pomerite je u desno.\n\n UREĐIVANJE\n Da biste uredili odeljak, samo ga jednom dodirnite.\n\n DODAVANJE\n Da biste dodali novi odeljak, pritisnite dugme +.',1779847536244,5,11,61);
