INSERT INTO votes VALUES(41867,'Här kan du namnge, beskriva och redigera innehållet i din session.\n\n OMORDNING\n För att omordna objekten, tryck länge på ett objekt och\n dra det till sin nya position.\n\n BORTTAGNING\n För att ta bort ett objekt, flytta det till höger.\n\n REDIGERA\n För att redigera en sektion, tryck bara på den en gång.\n\n LÄGG TILL\n För att lägga till en ny sektion, tryck på + knappen.',1779847616992,103,11,61);
