INSERT INTO votes VALUES(41915,'Burada Oturumunuzun adını, açıklamasını ve içeriğini düzenleyebilirsiniz.\n\n YENİDEN SIRALAMA\n Öğeleri yeniden sıralamak için, bir öğeye uzun basın ve\n yeni konumuna sürükleyin.\n\n SİLME\n Bir öğeyi silmek için sağa hareket ettirin.\n\n DÜZENLEME\n Bir bölümü düzenlemek için bir kez dokunun.\n\n EKLEME\n Yeni bir bölüm eklemek için + düğmesine basın.',1779847726082,111,11,61);
