INSERT INTO votes VALUES(42270,'هنا يمكنك تسمية ووصف وتعديل محتويات جلستك.\n\n إعادة الترتيب\n لإعادة ترتيب العناصر، اضغط مطولاً على عنصر و\n اسحبه إلى موضعه الجديد.\n\n الحذف\n لحذف عنصر، حركه إلى اليمين.\n\n التعديل\n لتعديل قسم، فقط المسه مرة واحدة.\n\n الإضافة\n لإضافة قسم جديد، اضغط على زر +.',1779848596757,3,13,61);
