INSERT INTO votes VALUES(42424,'Тут вы можаце назваць, апісаць і рэдагаваць змесціва вашай сесіі.\n\n ЗМЕНА ПАРАДКУ\n Каб змяніць парадак элементаў, доўга націскайце на элемент і\n перацягніце яго на новае месца.\n\n ВЫДАЛЕННЕ\n Каб выдаліць элемент, перамясціце яго ўправа.\n\n РЭДАГАВАННЕ\n Каб адрэдагаваць секцыю, проста дакраніцеся да яе адзін раз.\n\n ДАДАВАННЕ\n Каб дадаць новую секцыю, націсніце кнопку +.',1779848801445,6,13,61);
