INSERT INTO votes VALUES(42494,'Тук можете да наименувате, опишете и редактирате съдържанието на вашата Сесия.\n\n ПРЕПОДРЕЖДАНЕ\n За да пренаредите елементите, задръжте дълго върху елемент и\n го плъзнете на новата му позиция.\n\n ИЗТРИВАНЕ\n За да изтриете елемент, преместете го надясно.\n\n РЕДАКТИРАНЕ\n За да редактирате секция, просто я докоснете веднъж.\n\n ДОБАВЯНЕ\n За да добавите нова секция, натиснете бутона +.',1779848863483,7,13,61);
