INSERT INTO votes VALUES(42653,'মূলত Stefan Gaffga কর্তৃক তৈরি। বর্তমানে Georg Graf এর রক্ষণাবেক্ষণ করছেন।<br><br>অসাধারণ সব ঘণ্টার শব্দ প্রদান করার জন্য <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> এর Winfried কে ধন্যবাদ!',1779849013732,9,13,3);
INSERT INTO votes VALUES(42654,'এই অ্যাপ্লিকেশনের সাহায্যে ব্যবহারকারী বিভিন্ন মেডিটেশন সেশন তৈরি করতে পারবেন। এতে একটি টাইমার রয়েছে যা মেডিটেশনের কোনো একটি অংশ বা পুরো মেডিটেশন শেষ হলে ভিজ্যুয়াল এবং অডিও ফিডব্যাক প্রদান করে।',1779849013735,9,13,5);
