INSERT INTO votes VALUES(42671,'এখানে আপনি আপনার সেশনের নাম, বর্ণনা এবং বিষয়বস্তু সম্পাদনা করতে পারেন।\n\n পুনর্বিন্যাস\n আইটেমগুলি পুনর্বিন্যাস করতে, একটি আইটেম দীর্ঘক্ষণ চেপে ধরুন এবং\n এটিকে নতুন অবস্থানে টেনে আনুন।\n\n মুছে ফেলা\n একটি আইটেম মুছতে, এটিকে ডানদিকে সরান।\n\n সম্পাদনা\n একটি পর্ব সম্পাদনা করতে, কেবল একবার এটি স্পর্শ করুন।\n\n যোগ করা\n একটি নতুন পর্ব যোগ করতে, + বোতাম টিপুন।',1779849013780,9,13,61);
