INSERT INTO votes VALUES(43094,'Zde můžete pojmenovat, popsat a upravit obsah vašeho Sezení.\n\n PŘESUNUTÍ\n Chcete-li změnit pořadí položek, dlouze stiskněte položku a\n přetáhněte ji na novou pozici.\n\n MAZÁNÍ\n Chcete-li položku smazat, posuňte ji doprava.\n\n ÚPRAVA\n Chcete-li upravit sekci, stačí se jí jednou dotknout.\n\n PŘIDAT\n Chcete-li přidat novou sekci, stiskněte tlačítko +.',1779849392815,15,13,61);
