INSERT INTO votes VALUES(43213,'Her kan du navngive, beskrive og redigere indholdet af din session.\n\n OMBYTNING\n For at ændre rækkefølgen, tryk længe på et element og\n træk det til dets nye position.\n\n SLETNING\n For at slette et element, flyt det til højre.\n\n REDIGER\n For at redigere en sektion, skal du blot trykke på den en gang.\n\n TILFØJ\n For at tilføje en ny sektion, tryk på knappen +.',1779849517392,17,13,61);
