INSERT INTO votes VALUES(43237,'Ursprünglich erstellt von Stefan Gaffga. Aktuell gepflegt von Georg Graf.<br><br>Danke an Winfried von <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> für die Bereitstellung solch großartiger Klangschalen-Klänge!',1779849575487,18,13,3);
INSERT INTO votes VALUES(43238,'Diese Anwendung ermöglicht es dem Benutzer, eine Reihe von Meditationssitzungen zu definieren, und bietet einen Timer mit visuellem und akustischem Feedback, wenn ein Teil oder die gesamte Meditation beendet ist.',1779849575490,18,13,5);
