INSERT INTO votes VALUES(43241,'Reduziere die individuelle Lautstärke der Klangschalen für diese Session.',1779849575498,18,13,28);
INSERT INTO votes VALUES(43242,'Hier kannst du den Inhalt deiner Session benennen, beschreiben und bearbeiten.\n\n NEU ANORDNEN\n Um die Elemente neu anzuordnen, halte ein Element lange gedrückt und\n ziehe es an seine neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, schiebe es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippe ihn einfach einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücke den + Button.',1779849575501,18,13,61);
