INSERT INTO votes VALUES(43254,'Χρονόμετρο Διαλογισμού Zazen — Ένα απλό χρονόμετρο διαλογισμού με προσαρμόσιμες ενότητες, ήχους ηχογαβάθας και διαχείριση συνεδριών.',1779849710266,21,13,2);
