INSERT INTO votes VALUES(43329,'Ĉi tie vi povas nomi, priskribi kaj redakti la enhavon de via Seanco.\n\n REORDIGO\n Por reordigi la erojn, longe premu sur ero kaj\n trenu ĝin al ĝia nova pozicio.\n\n FORIGO\n Por forigi eron, movu ĝin dekstren.\n\n REDAKTO\n Por redakti sekcion, simple tuŝu ĝin unufoje.\n\n ALDONO\n Por aldoni novan sekcion, premu la + butonon.',1779849782644,22,13,61);
