INSERT INTO votes VALUES(43370,'Aquí puede nombrar, describir y editar el contenido de su sesión.\n\n REORDENAR\n Para reordenar los elementos, mantenga pulsado un elemento y\n arrástrelo a su nueva posición.\n\n ELIMINAR\n Para eliminar un elemento, muévalo a la derecha.\n\n EDITAR\n Para editar una sección, simplemente tóquela una vez.\n\n AÑADIR\n Para añadir una nueva sección, pulse el botón +.',1779849839795,23,13,61);
