INSERT INTO votes VALUES(43633,'در اینجا می‌توانید نام، توضیحات و محتوای جلسه خود را ویرایش کنید.\n\n مرتب‌سازی مجدد\n برای مرتب‌سازی مجدد موارد، روی یک مورد طولانی فشار دهید و\n آن را به موقعیت جدیدش بکشید.\n\n حذف\n برای حذف یک مورد، آن را به راست بکشید.\n\n ویرایش\n برای ویرایش یک بخش، فقط یک بار روی آن ضربه بزنید.\n\n افزودن\n برای افزودن یک بخش جدید، دکمه + را فشار دهید.',1779850050175,26,13,61);
