INSERT INTO votes VALUES(43839,'Minuteur de méditation Zazen — Un simple minuteur de méditation avec des sections personnalisables, des sons de cloche et une gestion de session.',1779850274623,29,13,2);
INSERT INTO votes VALUES(43840,'Créé à l''origine par Stefan Gaffga. Actuellement maintenu par Georg Graf.<br><br>Merci à Winfried de <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> pour avoir fourni de si superbes sons de cloche !',1779850274626,29,13,3);
