INSERT INTO votes VALUES(43842,'Cette application permet à l''utilisateur de définir un ensemble de sessions de méditation et fournit une minuterie avec un retour visuel et sonore lorsqu''une partie ou toute la méditation est terminée.',1779850274632,29,13,5);
