INSERT INTO votes VALUES(43855,'Ici, vous pouvez nommer, décrire et modifier le contenu de votre session.\n\n RÉORGANISER\n Pour réorganiser les éléments, appuyez longuement sur un élément et\n faites-le glisser vers sa nouvelle position.\n\n SUPPRIMER\n Pour supprimer un élément, déplacez-le vers la droite.\n\n MODIFIER\n Pour modifier une section, touchez-la simplement une fois.\n\n AJOUTER\n Pour ajouter une nouvelle section, appuyez sur le bouton +.',1779850274663,29,13,61);
INSERT INTO votes VALUES(43856,'Il n''y a aucune session qui puisse être démarrée. Veuillez d''abord en créer une.',1779850274665,29,13,80);
