INSERT INTO votes VALUES(43859,'Cette application ne collecte aucune donnée personnelle - elle n''utilise pas non plus d''adresses IP ou d''autres données liées à la technologie, et ne les collecte, ne les traite ou ne les utilise d''aucune manière.',1779850274673,29,13,100);
