INSERT INTO votes VALUES(44080,'Zazen Meditation Timer — Un temporizador de meditación sinxelo con seccións personalizables, sons de campá e xestión de sesións.',1779850489862,33,13,2);
INSERT INTO votes VALUES(44081,'Orixinalmente creado por Stefan Gaffga. Actualmente mantido por Georg Graf.<br><br>Grazas a Winfried de <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> por proporcionar uns sons de campá tan fantásticos!',1779850489865,33,13,3);
INSERT INTO votes VALUES(44082,'Esta aplicación permítelle ao usuario definir un conxunto de sesións de meditación e proporciona un temporizador con avisos visuais e sonoros cando remata unha parte ou toda a meditación.',1779850489867,33,13,5);
