INSERT INTO votes VALUES(44101,'Aquí pode nomear, describir e editar o contido da súa sesión.\n\n REORDENAR\n Para reordenar os elementos, manteña premido un elemento e\n arrástreo á súa nova posición.\n\n ELIMINAR\n Para eliminar un elemento, móvao cara á dereita.\n\n EDITAR\n Para editar unha sección, só ten que tocala unha vez.\n\n ENGADIR\n Para engadir unha nova sección, prema o botón +.',1779850489914,33,13,61);
