INSERT INTO votes VALUES(44467,'यहां आप अपने सेशन के कंटेंट का नाम, वर्णन और संपादन कर सकते हैं।\n\n रीऑर्डर करना\n आइटम को रीऑर्डर करने के लिए, किसी आइटम पर देर तक दबाएं और\n उसे उसकी नई स्थिति में खींचें।\n\n हटाना\n किसी आइटम को हटाने के लिए, उसे दाईं ओर ले जाएं।\n\n संपादन\n किसी सेक्शन को संपादित करने के लिए, बस उसे एक बार स्पर्श करें।\n\n जोड़ना\n नया सेक्शन जोड़ने के लिए, + बटन दबाएं।',1779850773700,37,13,61);
